import apiService from './apiService';

// ============ EXCEL API FUNCTIONS WITH ENHANCED DEBUGGING ============

export const getAllStudents = async (classId) => {
  try {
    console.log('🔄 ExcelAPI: Getting students for class:', classId);
    
    if (!classId) {
      throw new Error('Class ID is required');
    }
    
    const response = await apiService.getStudents(classId);
    
    console.log('📊 ExcelAPI: Students response:', {
      success: response.success,
      studentsCount: response.students?.length || 0,
      message: response.message,
      sampleData: response.students?.[0] || null,
      isMockData: response.isMockData || false
    });
    
    if (response.success && response.students && response.students.length > 0) {
      return {
        success: true,
        students: response.students,
        message: `Loaded ${response.students.length} students`,
        classId: classId,
        isMockData: response.isMockData || false
      };
    } else if (response.success && response.students && response.students.length === 0) {
      // Handle empty but successful response
      console.warn('⚠️ ExcelAPI: No students found for class:', classId);
      return {
        success: true,
        students: [],
        message: `No students found for class ${classId}`,
        classId: classId
      };
    } else {
      // If response is not successful, but we have error info
      console.error('❌ ExcelAPI: Students API returned unsuccessful response:', response);
      throw new Error(response.message || 'No students data received from API');
    }
  } catch (error) {
    console.error('❌ ExcelAPI: Get students error:', error);
    
    // Enhanced error handling with fallback
    if (process.env.NODE_ENV === 'development') {
      console.warn('🔧 ExcelAPI: Providing fallback empty students array for development');
      return {
        success: false,
        students: [],
        message: `Failed to load students: ${error.message}`,
        error: error.message,
        classId: classId,
        fallback: true
      };
    }
    
    throw error;
  }
};

export const getMonthlyAttendance = async ({ classId, month, year }) => {
  try {
    console.log('🔄 ExcelAPI: Getting monthly attendance:', { classId, month, year });
    
    // Enhanced validation
    if (!classId || !month || !year) {
      throw new Error('Class ID, month, and year are required');
    }
    
    if (month < 1 || month > 12) {
      throw new Error('Month must be between 1 and 12');
    }
    
    if (year < 2020 || year > 2030) {
      throw new Error('Year must be between 2020 and 2030');
    }
    
    const response = await apiService.getMonthlyAttendance(classId, month, year);
    
    console.log('📊 ExcelAPI: Monthly attendance response:', {
      success: response.success,
      attendanceCount: response.attendance?.length || 0,
      studentsCount: response.students?.length || 0,
      statistics: response.statistics,
      isMockData: response.isMockData || false,
      month: month,
      year: year
    });
    
    // Always return a consistent structure
    const result = {
      success: response.success || false,
      attendance: response.attendance || [],
      students: response.students || [],
      statistics: response.statistics || {
        totalPresent: 0,
        totalAbsent: 0,
        totalStudents: 0,
        attendancePercentage: 0
      },
      message: response.message || (response.success ? 'Monthly attendance loaded successfully' : 'Failed to load monthly attendance'),
      classId: classId,
      month: month,
      year: year,
      isMockData: response.isMockData || false
    };
    
    return result;
    
  } catch (error) {
    console.error('❌ ExcelAPI: Get monthly attendance error:', error);
    
    // Return fallback response structure for frontend compatibility
    return {
      success: false,
      attendance: [],
      students: [],
      statistics: {
        totalPresent: 0,
        totalAbsent: 0,
        totalStudents: 0,
        workingDays: new Date(year, month, 0).getDate(),
        attendancePercentage: 0
      },
      message: error.message || 'Failed to load monthly attendance',
      error: error.message,
      classId: classId,
      month: month,
      year: year,
      fallback: true
    };
  }
};

export const getDailyAttendance = async ({ classId, date }) => {
  try {
    console.log('🔄 ExcelAPI: Getting daily attendance:', { classId, date });
    
    // Enhanced validation
    if (!classId || !date) {
      throw new Error('Class ID and date are required');
    }
    
    // Validate date format
    const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
    if (!dateRegex.test(date)) {
      throw new Error('Date must be in YYYY-MM-DD format');
    }
    
    // Check if date is not in the future
    const inputDate = new Date(date);
    const today = new Date();
    today.setHours(23, 59, 59, 999); // End of today
    
    if (inputDate > today) {
      console.warn('⚠️ ExcelAPI: Requested date is in the future:', date);
    }
    
    const response = await apiService.getDailyAttendance(classId, date);
    
    console.log('📊 ExcelAPI: Daily attendance response:', {
      success: response.success,
      attendanceCount: response.attendance?.length || 0,
      studentsCount: response.students?.length || 0,
      statistics: response.statistics,
      isMockData: response.isMockData || false,
      date: date
    });
    
    // Always return a consistent structure
    const result = {
      success: response.success || false,
      attendance: response.attendance || [],
      students: response.students || [],
      statistics: response.statistics || {
        totalPresent: 0,
        totalAbsent: 0,
        totalLate: 0,
        totalStudents: 0,
        attendancePercentage: 0
      },
      message: response.message || (response.success ? 'Daily attendance loaded successfully' : 'Failed to load daily attendance'),
      classId: classId,
      date: date,
      isMockData: response.isMockData || false
    };
    
    return result;
    
  } catch (error) {
    console.error('❌ ExcelAPI: Get daily attendance error:', error);
    
    // Return fallback response structure
    return {
      success: false,
      attendance: [],
      students: [],
      statistics: {
        totalPresent: 0,
        totalAbsent: 0,
        totalLate: 0,
        totalStudents: 0,
        attendancePercentage: 0
      },
      message: error.message || 'Failed to load daily attendance',
      error: error.message,
      classId: classId,
      date: date,
      fallback: true
    };
  }
};

export const generateDailySheet = async (data) => {
  try {
    console.log('🔄 ExcelAPI: Generating daily sheet:', data);
    
    // Enhanced validation
    if (!data.classId) {
      throw new Error('Class ID is required for daily sheet generation');
    }
    
    if (!data.date) {
      data.date = new Date().toISOString().split('T')[0];
      console.log('📅 ExcelAPI: No date provided, using today:', data.date);
    }
    
    const response = await apiService.generateDailySheet(data);
    
    console.log('✅ ExcelAPI: Daily sheet generated:', {
      success: response.success,
      filename: response.filename,
      hasDownloadUrl: !!response.downloadUrl,
      statistics: response.statistics
    });
    
    if (response.success) {
      return {
        ...response,
        message: response.message || 'Daily sheet generated successfully',
        generatedAt: new Date().toISOString()
      };
    } else {
      throw new Error(response.message || 'Failed to generate daily sheet');
    }
    
  } catch (error) {
    console.error('❌ ExcelAPI: Generate daily sheet error:', error);
    throw {
      success: false,
      message: error.message || 'Failed to generate daily sheet',
      error: error.message,
      timestamp: new Date().toISOString()
    };
  }
};

export const generateMonthlyReport = async (data) => {
  try {
    console.log('🔄 ExcelAPI: Generating monthly report:', data);
    
    // Enhanced validation
    if (!data.classId) {
      throw new Error('Class ID is required for monthly report generation');
    }
    
    if (!data.month || !data.year) {
      throw new Error('Month and year are required for monthly report generation');
    }
    
    if (data.month < 1 || data.month > 12) {
      throw new Error('Month must be between 1 and 12');
    }
    
    if (data.year < 2020 || data.year > 2030) {
      throw new Error('Year must be between 2020 and 2030');
    }
    
    const response = await apiService.generateMonthlyReport(data);
    
    console.log('✅ ExcelAPI: Monthly report generated:', {
      success: response.success,
      filename: response.filename,
      hasDownloadUrl: !!response.downloadUrl,
      statistics: response.statistics,
      month: data.month,
      year: data.year
    });
    
    if (response.success) {
      return {
        ...response,
        message: response.message || `Monthly report generated successfully for ${data.month}/${data.year}`,
        generatedAt: new Date().toISOString(),
        reportPeriod: `${data.month}/${data.year}`
      };
    } else {
      throw new Error(response.message || 'Failed to generate monthly report');
    }
    
  } catch (error) {
    console.error('❌ ExcelAPI: Generate monthly report error:', error);
    throw {
      success: false,
      message: error.message || 'Failed to generate monthly report',
      error: error.message,
      timestamp: new Date().toISOString()
    };
  }
};

export const getReportsList = async (classId) => {
  try {
    console.log('🔄 ExcelAPI: Getting reports list:', classId);
    
    if (!classId) {
      throw new Error('Class ID is required for reports list');
    }
    
    const response = await apiService.getReportsList(classId);
    
    console.log('✅ ExcelAPI: Reports list retrieved:', {
      success: response.success,
      dailyReports: response.reports?.daily?.length || 0,
      monthlyReports: response.reports?.monthly?.length || 0,
      totalReports: (response.reports?.daily?.length || 0) + (response.reports?.monthly?.length || 0)
    });
    
    // Ensure consistent structure
    const result = {
      success: response.success || true,
      reports: {
        daily: response.reports?.daily || [],
        monthly: response.reports?.monthly || []
      },
      message: response.message || 'Reports list retrieved successfully',
      classId: classId,
      totalDailyReports: response.reports?.daily?.length || 0,
      totalMonthlyReports: response.reports?.monthly?.length || 0
    };
    
    return result;
    
  } catch (error) {
    console.error('❌ ExcelAPI: Get reports list error:', error);
    
    // Return fallback for frontend compatibility
    return {
      success: false,
      reports: { 
        daily: [], 
        monthly: [] 
      },
      message: error.message || 'Reports list not available',
      error: error.message,
      classId: classId,
      totalDailyReports: 0,
      totalMonthlyReports: 0,
      fallback: true
    };
  }
};

// ============ CAMERA AND UPLOAD FUNCTIONS ============

export const captureAttendanceViaCamera = async (imageData, classId) => {
  try {
    console.log('📸 ExcelAPI: Capturing attendance via camera for class:', classId);
    
    if (!imageData) {
      throw new Error('Image data is required for camera capture');
    }
    
    if (!classId) {
      throw new Error('Class ID is required for camera capture');
    }
    
    // Validate image data format
    if (typeof imageData !== 'string' || !imageData.startsWith('data:image/')) {
      throw new Error('Invalid image data format. Expected base64 data URL.');
    }
    
    const response = await apiService.captureAttendance({
      imageData: imageData,
      classId: classId,
      timestamp: new Date().toISOString()
    });
    
    console.log('✅ ExcelAPI: Camera capture completed:', {
      success: response.success,
      recognizedCount: response.recognizedStudents?.length || 0,
      markedCount: response.attendanceMarked?.length || 0
    });
    
    return response;
  } catch (error) {
    console.error('❌ ExcelAPI: Camera capture error:', error);
    throw {
      success: false,
      message: error.message || 'Failed to capture attendance via camera',
      error: error.message,
      timestamp: new Date().toISOString()
    };
  }
};

export const uploadPhotosForAttendance = async (images, classId, options = {}) => {
  try {
    console.log('📤 ExcelAPI: Uploading photos for attendance:', {
      imageCount: images?.length || 0,
      classId: classId,
      options: options
    });
    
    if (!images || !Array.isArray(images) || images.length === 0) {
      throw new Error('At least one image is required for photo upload');
    }
    
    if (!classId) {
      throw new Error('Class ID is required for photo upload');
    }
    
    // Check for large batch uploads
    if (images.length > 20) {
      console.warn('⚠️ ExcelAPI: Large batch upload detected. Consider processing in smaller batches.');
    }
    
    const uploadData = {
      images: images,
      classId: classId,
      uploadType: options.uploadType || 'batch',
      timestamp: new Date().toISOString(),
      ...options
    };
    
    const response = await apiService.uploadPhotosForAttendance(uploadData);
    
    console.log('✅ ExcelAPI: Photo upload completed:', {
      success: response.success,
      totalProcessed: response.results?.totalPhotosProcessed || 0,
      recognizedCount: response.results?.recognizedStudents?.length || 0,
      markedCount: response.results?.markedAttendance?.length || 0
    });
    
    return response;
  } catch (error) {
    console.error('❌ ExcelAPI: Photo upload error:', error);
    throw {
      success: false,
      message: error.message || 'Failed to upload photos for attendance',
      error: error.message,
      timestamp: new Date().toISOString()
    };
  }
};

// ============ UTILITY FUNCTIONS ============

export const exportAttendanceToCSV = (students, attendanceData, mode, options = {}) => {
  try {
    console.log('📥 ExcelAPI: Exporting to CSV:', { 
      mode, 
      studentsCount: students.length, 
      attendanceCount: attendanceData.length 
    });
    
    if (!students || students.length === 0) {
      throw new Error('No students data available for export');
    }
    
    const data = [];
    const { classId, selectedMonth, selectedYear, selectedDate } = options;
    
    if (mode === 'monthly') {
      const headers = ['Student ID', 'Student Name'];
      const daysInMonth = new Date(selectedYear, selectedMonth, 0).getDate();
      
      // Add day columns
      for (let day = 1; day <= daysInMonth; day++) {
        headers.push(day.toString());
      }
      headers.push('Total Present', 'Total Absent', 'Total Late', 'Percentage');
      data.push(headers);
      
      // Add student rows
      students.forEach(student => {
        const row = [student.studentId, student.name];
        let presentCount = 0;
        let absentCount = 0;
        let lateCount = 0;
        
        for (let day = 1; day <= daysInMonth; day++) {
          const date = `${selectedYear}-${selectedMonth.toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
          const attendance = attendanceData.find(att => 
            att.studentId === student.studentId && att.date === date
          );
          
          const status = attendance ? attendance.status : 'Absent';
          const symbol = getStatusSymbol(status);
          
          row.push(symbol);
          
          if (status === 'Present') presentCount++;
          else if (status === 'Late') lateCount++;
          else absentCount++;
        }
        
        const totalDays = presentCount + absentCount + lateCount;
        const percentage = totalDays > 0 ? ((presentCount + lateCount) / totalDays * 100).toFixed(1) : 0;
        row.push(presentCount, absentCount, lateCount, `${percentage}%`);
        data.push(row);
      });
      
    } else { // daily mode
      const headers = ['Student ID', 'Student Name', 'Status', 'Time In', 'Method', 'Confidence', 'Notes'];
      data.push(headers);
      
      students.forEach(student => {
        const attendance = attendanceData.find(att => att.studentId === student.studentId);
        const row = [
          student.studentId,
          student.name,
          attendance ? attendance.status : 'Absent',
          attendance ? (attendance.timeIn || attendance.timestamp?.split('T')[1]?.split('.')[0] || 'N/A') : 'N/A',
          attendance ? (attendance.method || 'Manual') : 'N/A',
          attendance && attendance.confidence ? `${(attendance.confidence * 100).toFixed(1)}%` : 'N/A',
          attendance ? (attendance.notes || '') : ''
        ];
        data.push(row);
      });
    }
    
    // Create CSV content with proper escaping
    const csvContent = data.map(row => 
      row.map(cell => {
        const cellStr = String(cell || '');
        // Escape cells containing commas, quotes, or newlines
        if (cellStr.includes(',') || cellStr.includes('"') || cellStr.includes('\n')) {
          return `"${cellStr.replace(/"/g, '""')}"`;
        }
        return cellStr;
      }).join(',')
    ).join('\n');
    
    // Add BOM for proper Excel handling of UTF-8
    const BOM = '\uFEFF';
    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    
    // Generate filename
    const timestamp = new Date().toISOString().split('T')[0];
    const filename = `attendance_${classId}_${mode === 'monthly' ? `${selectedYear}-${selectedMonth.toString().padStart(2, '0')}` : selectedDate}_${timestamp}.csv`;
    
    // Download file
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    link.style.display = 'none';
    
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);
    
    console.log('✅ ExcelAPI: CSV exported successfully:', {
      filename: filename,
      recordCount: data.length - 1,
      mode: mode
    });
    
    return {
      success: true,
      message: `Successfully exported ${data.length - 1} records`,
      filename: filename,
      recordCount: data.length - 1,
      exportedAt: new Date().toISOString()
    };
    
  } catch (error) {
    console.error('❌ ExcelAPI: CSV export error:', error);
    throw {
      success: false,
      message: error.message || 'Failed to export CSV',
      error: error.message
    };
  }
};

// Helper function for status symbols
const getStatusSymbol = (status) => {
  switch (status) {
    case 'Present': return '✓';
    case 'Absent': return '✗';
    case 'Late': return '⏰';
    case 'Excused': return '📋';
    default: return '-';
  }
};

// ============ DATA VALIDATION UTILITIES ============

export const validateAttendanceData = (attendanceData) => {
  try {
    if (!Array.isArray(attendanceData)) {
      return { valid: false, error: 'Attendance data must be an array' };
    }
    
    const issues = [];
    
    attendanceData.forEach((record, index) => {
      if (!record.studentId) {
        issues.push(`Record ${index + 1}: Missing student ID`);
      }
      
      if (!record.status) {
        issues.push(`Record ${index + 1}: Missing status`);
      }
      
      if (!record.date && !record.timestamp) {
        issues.push(`Record ${index + 1}: Missing date/timestamp`);
      }
    });
    
    return {
      valid: issues.length === 0,
      issues: issues,
      recordCount: attendanceData.length
    };
    
  } catch (error) {
    return {
      valid: false,
      error: error.message
    };
  }
};

export const validateStudentsData = (studentsData) => {
  try {
    if (!Array.isArray(studentsData)) {
      return { valid: false, error: 'Students data must be an array' };
    }
    
    const issues = [];
    const studentIds = new Set();
    
    studentsData.forEach((student, index) => {
      if (!student.studentId) {
        issues.push(`Student ${index + 1}: Missing student ID`);
      } else if (studentIds.has(student.studentId)) {
        issues.push(`Student ${index + 1}: Duplicate student ID: ${student.studentId}`);
      } else {
        studentIds.add(student.studentId);
      }
      
      if (!student.name) {
        issues.push(`Student ${index + 1}: Missing name`);
      }
    });
    
    return {
      valid: issues.length === 0,
      issues: issues,
      studentCount: studentsData.length,
      uniqueStudents: studentIds.size
    };
    
  } catch (error) {
    return {
      valid: false,
      error: error.message
    };
  }
};

// ============ BATCH OPERATIONS ============

export const batchProcessAttendance = async (operations) => {
  try {
    console.log('🔄 ExcelAPI: Processing batch operations:', operations.length);
    
    const results = [];
    const errors = [];
    
    for (let i = 0; i < operations.length; i++) {
      const operation = operations[i];
      
      try {
        let result;
        
        switch (operation.type) {
          case 'getStudents':
            result = await getAllStudents(operation.classId);
            break;
          case 'getMonthlyAttendance':
            result = await getMonthlyAttendance(operation);
            break;
          case 'getDailyAttendance':
            result = await getDailyAttendance(operation);
            break;
          case 'generateDailySheet':
            result = await generateDailySheet(operation.data);
            break;
          case 'generateMonthlyReport':
            result = await generateMonthlyReport(operation.data);
            break;
          default:
            throw new Error(`Unknown operation type: ${operation.type}`);
        }
        
        results.push({
          operationId: operation.id || i,
          type: operation.type,
          success: true,
          result: result
        });
        
      } catch (error) {
        errors.push({
          operationId: operation.id || i,
          type: operation.type,
          success: false,
          error: error.message
        });
      }
    }
    
    console.log('✅ ExcelAPI: Batch processing completed:', {
      total: operations.length,
      successful: results.length,
      failed: errors.length
    });
    
    return {
      success: errors.length === 0,
      results: results,
      errors: errors,
      summary: {
        total: operations.length,
        successful: results.length,
        failed: errors.length
      }
    };
    
  } catch (error) {
    console.error('❌ ExcelAPI: Batch processing error:', error);
    throw {
      success: false,
      message: error.message || 'Failed to process batch operations',
      error: error.message
    };
  }
};

// ============ ENHANCED DEFAULT EXPORT ============

export default {
  // Core functions
  getAllStudents,
  getMonthlyAttendance,
  getDailyAttendance,
  generateDailySheet,
  generateMonthlyReport,
  getReportsList,
  
  // Camera and upload functions
  captureAttendanceViaCamera,
  uploadPhotosForAttendance,
  
  // Utility functions
  exportAttendanceToCSV,
  validateAttendanceData,
  validateStudentsData,
  batchProcessAttendance,
  
  // Helper functions
  getStatusSymbol: (status) => getStatusSymbol(status),
  
  // Grouped functions for easy access
  attendance: {
    getMonthly: getMonthlyAttendance,
    getDaily: getDailyAttendance,
    capture: captureAttendanceViaCamera,
    upload: uploadPhotosForAttendance
  },
  
  students: {
    getAll: getAllStudents,
    validate: validateStudentsData
  },
  
  reports: {
    generateDaily: generateDailySheet,
    generateMonthly: generateMonthlyReport,
    getList: getReportsList
  },
  
  export: {
    toCSV: exportAttendanceToCSV
  },
  
  validation: {
    attendance: validateAttendanceData,
    students: validateStudentsData
  },
  
  batch: {
    process: batchProcessAttendance
  }
};
